// Import of required libraries
import { test } from '@playwright/test';
import { expect, newSkyrampPlaywrightPage } from '@skyramp/skyramp';

const pageTimeout = 15000;

test('testUi', async ({ page }) => {
    test.setTimeout(60000);

    // set default timeout for all locator/page actions in this test
    page.setDefaultTimeout(pageTimeout);
    // Wrap playwright page with Skyramp page
    page = newSkyrampPlaywrightPage(page);

    const pageErrors: Error[] = [];
    page.on('pageerror', (error) => pageErrors.push(error));

    await page.goto("http://localhost:8055/admin/files/+");
    await page.getByRole("textbox", { name: "Email" }).fill("admin@example.com");
    await page.getByRole("textbox", { name: "Password" }).fill("admin");
    const loginRespPromise = page.waitForResponse("**/auth/login**");
    await page.getByRole("button", { name: "Sign In" }).click();
    const loginResp = await loginRespPromise;
    expect(loginResp.status()).toBe(200);
    await page.getByRole("button", { name: "Remind Later" }).click();
    await expect(page).toHaveURL(/\/admin\/files\/\+/);
    await expect(page.getByRole('button', { name: 'Choose File' })).toBeVisible();
    await page.getByRole("button", { name: "Done" }).click();
    await expect(page).toHaveURL(/\/admin\/files$/);
    await expect(page.getByRole('heading', { level: 1 })).toHaveText('File Library');

    expect(pageErrors).toHaveLength(0);
});
